const input = $input.first().json;
const artikelText = (input.artikelText || "").trim();

const systemMessage = `Du bist ein KMU-Business-Analyst. Analysiere die Artikel und liefere die TOP 5 Themen als JSON-Array mit VOLLSTÄNDIGEN Objekten.

PFLICHTFORMAT - Antworte NUR mit diesem JSON, KEIN Markdown, KEINE Erklärungen:
[
  {
    "thema": "Titel des Themas",
    "beschreibung": "Kurze Beschreibung max 200 Zeichen",
    "branchen": ["Maschinenbau", "IT"],
    "quellen_url": "https://beispiel.de/artikel",
    "weitere_quellen": "https://quelle2.de",
    "peer_advisory_board_kontext": "Diskussionsimpuls für Peer Advisory Board max 400 Zeichen",
    "relevanz_score": 8
  }
]

WICHTIG: Jedes der 5 Objekte MUSS alle 7 Felder enthalten. Kein Markdown. Kein Text außerhalb des Arrays.`;

const userContent = `Analysiere diese Artikel und erstelle die TOP 5 Themen-Liste im oben definierten JSON-Format:

${artikelText}

---
Antworte jetzt NUR mit dem JSON-Array (5 vollständige Objekte mit allen 7 Feldern):`;

return {
  requestBody: {
    model: "gpt-4o",
    messages: [
      { role: "system", content: systemMessage },
      { role: "user", content: userContent }
    ],
    temperature: 0.2
  }
};

// ============================================================
// V6 NEU: DEBUG - API Response Inspektion
// Zeigt die rohe Antwort der Abacus AI API an, damit man
// die tatsächliche Struktur sehen kann.
// ============================================================

const raw = $input.first().json;

// Typ und Struktur der Response analysieren
const responseType = typeof raw;
const topLevelKeys = responseType === 'object' && raw !== null ? Object.keys(raw) : [];

// Prüfe verschiedene mögliche Pfade zur Antwort
const debugInfo = {
  _debug_response_type: responseType,
  _debug_top_level_keys: topLevelKeys.join(', ') || '(keine)',
  _debug_has_choices: !!(raw && raw.choices),
  _debug_has_data: !!(raw && raw.data),
  _debug_has_body: !!(raw && raw.body),
  _debug_has_message: !!(raw && raw.message),
  _debug_has_content: !!(raw && raw.content),
  _debug_has_text: !!(raw && raw.text),
  _debug_is_string: responseType === 'string',
  _debug_raw_preview: responseType === 'string'
    ? raw.substring(0, 500)
    : JSON.stringify(raw).substring(0, 500)
};

// Alles durchreichen plus Debug-Info
return [{
  json: {
    ...raw,
    _debug: debugInfo
  }
}];

const response = $input.first().json;

let datum = new Date().toISOString().split('T')[0];

// Rohen Content holen
let rawContent = response.choices?.[0]?.message?.content || "";

// Markdown-Wrapper entfernen (```json ... ``` oder ``` ... ```)
rawContent = rawContent
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

// JSON-Array extrahieren
let themen = [];

// Versuch 1: Direkt parsen
try {
  const parsed = JSON.parse(rawContent);
  if (Array.isArray(parsed)) themen = parsed;
} catch(e) {}

// Versuch 2: Array per Regex finden
if (themen.length === 0) {
  const match = rawContent.match(/\[\s*[\s\S]*\]/);
  if (match) {
    try { themen = JSON.parse(match[0]); } catch(e) {}
  }
}

if (themen.length === 0) {
  throw new Error("Kein JSON-Array gefunden. Raw: " + rawContent.substring(0, 300));
}

// Für Notion aufbereiten
return themen.slice(0, 5).map((thema, idx) => {

  // Falls KI nur Strings liefert (Fallback)
  if (typeof thema === 'string') {
    return {
      json: {
        thema: thema,
        datum: datum,
        ranking: idx + 1,
        beschreibung: "",
        branchen: [],
        quellen_url: null,
        weitere_quellen: "",
        peer_advisory_board_kontext: "",
        relevanz_score: 5
      }
    };
  }

  // URL validieren (Notion akzeptiert kein "")
  const rawUrl = thema.quellen_url || thema.quellen || "";
  const validUrl = rawUrl.startsWith('http') ? rawUrl : null;

  return {
    json: {
      thema: String(thema.thema || `Thema ${idx + 1}`).substring(0, 200),
      datum: datum,
      ranking: idx + 1,
      beschreibung: String(thema.beschreibung || "").substring(0, 1900),
      branchen: Array.isArray(thema.branchen) ? thema.branchen : [],
      quellen_url: validUrl,
      weitere_quellen: String(thema.weitere_quellen || "").substring(0, 1900),
      peer_advisory_board_kontext: String(thema.peer_advisory_board_kontext || thema.peer_advisory_context || "").substring(0, 1900),
      relevanz_score: Math.min(10, Math.max(1, Number(thema.relevanz_score) || 5))
    }
  };
});

