// ============================================================
// V6: Ergebnis-Zusammenfassung
// Erstellt einen Überblick über den gesamten Workflow-Durchlauf
// ============================================================

const notionResults = $input.all();

let artikelAnzahl = 0;
let fehlerAnzahl = 0;
try {
  const artikelDaten = $('Artikel konsolidieren (v3)').first().json;
  artikelAnzahl = artikelDaten.artikelAnzahl || 0;
  fehlerAnzahl = artikelDaten.fehlerAnzahl || 0;
} catch (e) {
  // Fallback wenn Node nicht erreichbar
}

const erfolgreich = notionResults.filter(r => !r.json.error && r.json.id).length;
const fehlgeschlagen = notionResults.length - erfolgreich;

const zusammenfassung = {
  workflow: 'KMU Top-Themen Daily Recherche v6 (Abacus AI - Fixed)',
  datum: new Date().toISOString(),
  ergebnis: {
    artikel_gesammelt: artikelAnzahl,
    quellen_fehler: fehlerAnzahl,
    themen_erstellt: erfolgreich,
    themen_fehlgeschlagen: fehlgeschlagen
  },
  status: fehlgeschlagen === 0 ? 'Erfolgreich' : 'Teilweise erfolgreich',
  details: erfolgreich > 0 
    ? `${erfolgreich} von ${notionResults.length} Themen erfolgreich in Notion gespeichert.`
    : 'WARNUNG: Keine Themen konnten gespeichert werden!'
};

return [{ json: zusammenfassung }];

// ============================================================
// Fehler-Logging
// ============================================================

const zusammenfassung = $input.first().json;

console.error('=== WORKFLOW FEHLER ===');
console.error(`Datum: ${zusammenfassung.datum}`);
console.error(`Status: ${zusammenfassung.status}`);
console.error(`Details: ${zusammenfassung.details}`);
console.error('======================');

return [{
  json: {
    type: 'error_notification',
    subject: `⚠️ KMU Workflow v6: ${zusammenfassung.status}`,
    body: `Der KMU Top-Themen Workflow hatte Probleme:\n\n${zusammenfassung.details}`,
    zusammenfassung: zusammenfassung
  }
}];

// ============================================================
// Erfolgs-Logging
// ============================================================

const zusammenfassung = $input.first().json;

console.log('=== WORKFLOW v6 ERFOLGREICH ===');
console.log(`Datum: ${zusammenfassung.datum}`);
console.log(`Artikel gesammelt: ${zusammenfassung.ergebnis.artikel_gesammelt}`);
console.log(`Themen erstellt: ${zusammenfassung.ergebnis.themen_erstellt}`);
console.log('===============================');

return [{
  json: {
    type: 'success',
    message: `✅ ${zusammenfassung.ergebnis.themen_erstellt} KMU-Themen erfolgreich in Notion gespeichert. (Workflow v6)`,
    zusammenfassung: zusammenfassung
  }
}];

// Zeigt die Daten, die zur KI gehen
return $input.all().map(item => ({
  json: {
    debug_input: item.json,
    debug_timestamp: new Date().toISOString()
  }
}));

// ====================================================================
// FEATURE 1: XML-Parser - Strukturierte Daten aus RSS/Atom XML
// Extrahiert pro Feed max. 10 Artikel: Titel, Beschreibung, Link,
// Datum, Autor. Spart KI-Tokens durch Vorverarbeitung.
// ====================================================================

const items = $input.all();
const alleParsed = [];

function getTag(xml, tag) {
  const re = new RegExp(
    '<' + tag + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/' + tag + '>'
    + '|<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>', 'i');
  const m = xml.match(re);
  return (m ? (m[1] || m[2] || '') : '').trim();
}

function cleanHtml(s) {
  return s.replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#0?39;/g, "'").replace(/\s+/g, ' ')
    .substring(0, 500);
}

for (const item of items) {
  const rssContent = item.json.data || item.json.rssContent || item.json.content || '';
  const name = item.json.name || item.json.url || 'Unbekannt';
  const url = item.json.url || '';
  const kategorie = item.json.kategorie || '';
  const datum = item.json.datum || '';
  const datumDE = item.json.datumDE || '';

  if (!rssContent) continue;

  const artikel = [];

  // --- RSS 2.0 ---
  if (rssContent.includes('<rss') || (rssContent.includes('<channel') && !rssContent.includes('<feed'))) {
    const matches = rssContent.match(/<item[\s>][\s\S]*?<\/item>/gi) || [];
    for (const m of matches.slice(0, 10)) {
      const titel = getTag(m, 'title');
      if (!titel) continue;
      artikel.push({
        titel: titel,
        link: getTag(m, 'link'),
        beschreibung: cleanHtml(getTag(m, 'description')),
        datum: getTag(m, 'pubDate') || getTag(m, 'dc:date'),
        autor: getTag(m, 'dc:creator') || getTag(m, 'author')
      });
    }
  }

  // --- Atom ---
  if (rssContent.includes('<feed')) {
    const matches = rssContent.match(/<entry[\s>][\s\S]*?<\/entry>/gi) || [];
    for (const m of matches.slice(0, 10)) {
      const titel = getTag(m, 'title');
      if (!titel) continue;
      const linkMatch = m.match(/<link[^>]*href=["']([^"']+)["'][^>]*\/?>/);
      const autorMatch = m.match(/<author>[\s\S]*?<name>([\s\S]*?)<\/name>[\s\S]*?<\/author>/i);
      artikel.push({
        titel: titel,
        link: linkMatch ? linkMatch[1] : '',
        beschreibung: cleanHtml(getTag(m, 'summary') || getTag(m, 'content')),
        datum: getTag(m, 'published') || getTag(m, 'updated'),
        autor: autorMatch ? autorMatch[1].trim() : ''
      });
    }
  }

  if (artikel.length > 0) {
    alleParsed.push({ json: {
      quelleName: name,
      quelleUrl: url,
      kategorie: kategorie,
      datum: datum,
      datumDE: datumDE,
      artikelAnzahl: artikel.length,
      artikel: artikel
    }});
  }
}

const total = alleParsed.reduce(function(s, i) { return s + i.json.artikelAnzahl; }, 0);
console.log('Quellen geparst: ' + alleParsed.length + ', Artikel extrahiert: ' + total);
if (alleParsed.length === 0) throw new Error('Keine Artikel extrahiert!');
return alleParsed;

// ====================================================================
// Artikel-Aggregator: Fasst alle Quellen zusammen, erstellt
// Token-optimierten Text-Input für den KI-Node
// ====================================================================

const items = $input.all();
const datum   = items[0]?.json?.datum   || new Date().toISOString().split('T')[0];
const datumDE = items[0]?.json?.datumDE || '';

const alleArtikel = [];
for (const item of items) {
  for (const a of item.json.artikel) {
    alleArtikel.push({
      titel: a.titel, quelle: item.json.quelleName,
      kategorie: item.json.kategorie, link: a.link,
      beschreibung: a.beschreibung, datum: a.datum, autor: a.autor
    });
  }
}

const artikelText = alleArtikel.map((a, i) =>
  `[${i+1}] ${a.titel}\nQuelle: ${a.quelle} | Kategorie: ${a.kategorie}\n${a.beschreibung}\nLink: ${a.link}\nDatum: ${a.datum}${a.autor ? ' | Autor: '+a.autor : ''}`
).join('\n---\n');

console.log(`📊 ${alleArtikel.length} Artikel aggregiert aus ${items.length} Quellen`);

return [{ json: { datum, datumDE, artikelAnzahl: alleArtikel.length, quellenAnzahl: items.length, artikelText, artikelRaw: alleArtikel } }];

